#include <bits/stdc++.h>
using namespace std;
int n,c,a[100005],l=1,r=100000,mid,ans;
int judge(int mid)
{
    int t=a[0],num=0;
    for(int i=1;i<n;i++)
    {
        if(a[i]-t>=mid)
        {
            t=a[i];
            num++;
        }
        if(num==c-1)
        {
            return 1;
        }
    }
    return 0;
}
int main()
{
    cin>>n>>c;
    for(int i=0;i<n;i++)
    {
        cin>>a[i];
    }
    sort(a,a+n);
    while(l<=r)
    {
        mid=(l+r)/2;
        if(judge(mid))
        {
            l=mid+1;
            ans=mid;
        }
        else{
            r=mid-1;
        }
    }
    cout<<ans;
    return 0;
}
